sql_answer:
SELECT architect_id FROM bridge
EXCEPT
SELECT architect_id FROM mill;

SELECT id FROM bridge
INTERSECT
SELECT built_year FROM mill;

SELECT fault_description FROM Fault_Log
EXCEPT
SELECT fault_description FROM Part_Faults;

SELECT *
FROM Engineer_Visits
WHERE contact_staff_id IS NULL;

SELECT T1.*
FROM Maintenance_Contracts AS T1
WHERE T1.maintenance_contract_company_id IN (SELECT T2.supplier_company_id FROM Assets AS T2);

SELECT Major, COUNT(*) AS so_luong_sinh_vien
FROM Student
GROUP BY Major;

SELECT
  100.0 * COUNT(CASE WHEN T1.gender_code = 'Female' THEN 1 END) / COUNT(T1.guest_id)
FROM Guests AS T1;

SELECT *
FROM Apartment_Buildings
WHERE building_address LIKE '% AL %' OR building_address LIKE '% CA %';

SELECT T1.apt_id
FROM Apartments AS T1
WHERE T1.bathroom_count = (SELECT bathroom_count FROM Apartments WHERE apt_id = 1) AND T1.apt_id != 1;

SELECT *
FROM Apartment_Bookings
WHERE JULIANDAY(booking_end_date) - JULIANDAY(booking_start_date) > (
  SELECT AVG(JULIANDAY(booking_end_date) - JULIANDAY(booking_start_date))
  FROM Apartment_Bookings
);

SELECT Fname, LName
FROM Student
WHERE Major = 600;

SELECT *
FROM Student
WHERE Sex = 'M' OR Major = 540;

SELECT T1.Allergy FROM Allergy_Type AS T1 WHERE T1.AllergyType = 'food'
EXCEPT
SELECT T2.Allergy FROM Has_Allergy AS T2;

SELECT Fname, LName, city_code
FROM Student
WHERE city_code IN ('BAL', 'WAS');

SELECT name
FROM Web_client_accelerator
WHERE Operating_system = 'Windows';

SELECT name
FROM Web_client_accelerator
ORDER BY name ASC;

SELECT Num_of_shaff_in_charge
FROM happy_hour
WHERE Month = 'May' AND Shop_ID = 1;

SELECT Address FROM shop
INTERSECT
SELECT Address FROM member;

SELECT email_address FROM Students
UNION
SELECT email_address FROM Teachers;

SELECT T1.first_name, T1.last_name
FROM Students AS T1
WHERE T1.address_id NOT IN (SELECT T2.address_id FROM Student_Addresses AS T2);

SELECT City
FROM city
WHERE Regional_Population BETWEEN 5000000 AND 10000000;

WITH Shanghai_GDP AS (
  SELECT GDP AS val
  FROM city
  WHERE City = 'Shanghai'
), Total_GDP AS (
  SELECT SUM(GDP) AS total_val
  FROM city
)
SELECT T1.val * 100.0 / T2.total_val
FROM Shanghai_GDP AS T1, Total_GDP AS T2;

SELECT T1.City_ID FROM temperature AS T1
INTERSECT
SELECT T2.Host_City FROM hosting_city AS T2;

SELECT
  COUNT(T1.Match_ID)
FROM match AS T1
WHERE
  T1.Competition = '2002 FIFA World Cup qualification'
  AND CAST(
    SUBSTR(REPLACE(T1.Result, '–', '-'), 1, INSTR(REPLACE(T1.Result, '–', '-'), '-') - 1) AS INTEGER
  ) - CAST(
    SUBSTR(REPLACE(T1.Result, '–', '-'), INSTR(REPLACE(T1.Result, '–', '-'), '-') + 1) AS INTEGER
  ) >= 5;

SELECT DNO
FROM Department
WHERE DName = 'History of Art';

SELECT *
FROM Department
WHERE DNO = 600;

SELECT Building FROM Faculty WHERE Room = '224B'
UNION
SELECT Building FROM Department WHERE Room = '224B';

SELECT CName
FROM Course
WHERE Credits != 3;

SELECT *
FROM Student
WHERE city_code IN ('BAL', 'NYC');

SELECT lettergrade
FROM Gradeconversion
WHERE gradepoint BETWEEN 2.0 AND 3.5;

SELECT DNO FROM Minor_in
INTERSECT
SELECT DNO FROM Course;

SELECT CName
FROM Course
WHERE Credits = (
  SELECT MAX(Credits)
  FROM Course
);

SELECT Fname, LName
FROM Student
WHERE Age > (SELECT AVG(Age) FROM Student);

SELECT DISTINCT T1.Instructor
FROM Course AS T1
WHERE T1.Credits = LENGTH(T1.CName);

SELECT Fname, LName, Age
FROM Student
ORDER BY Age DESC;

SELECT Fname, LName
FROM Student
WHERE Age = (SELECT DISTINCT Age FROM Student ORDER BY Age DESC LIMIT 1 OFFSET 1);
